+type MetricKind = "latency" | "cpu" | "throughput" | "errors" | "queue";
+type MotionState = "falling" | "settled";
+
+type MetricDefinition = {
+  kind: MetricKind;
+  label: string;
+  unit: string;
+  symbol: string;
+  shape: string;
+  min: number;
+  max: number;
