+  height: number;
+  y: number;
+  velocity: number;
+  state: MotionState;
+  createdAt: number;
+};
+
+type FeedEvent = {
+  id: number;
+  kind: MetricKind;
+  label: string;
+  symbol: string;
+  value: string;
+  tone: "normal" | "warn" | "hot";
+};
+
+type StageSize = {
+  width: number;
+  height: number;
+};
+
+const METRICS: MetricDefinition[] = [
+  {
+    kind: "latency",
+    label: "API latency",
+    unit: "ms",
+    symbol: "L",
+    shape: "stripe",
+    min: 60,
+    max: 520,
+  },
+  {
+    kind: "cpu",
+    label: "CPU load",
+    unit: "%",
+    symbol: "C",
+    shape: "dots",
+    min: 18,
+    max: 96,
+  },
+  {
+    kind: "throughput",
+    label: "Requests",
+    unit: "/s",
+    symbol: "R",
+    shape: "grid",
+    min: 900,
+    max: 6400,
+  },
+  {
+    kind: "errors",
+    label: "Error rate",
+    unit: "%",
+    symbol: "E",
+    shape: "slash",
+    min: 0,
+    max: 9,
+  },
+  {
+    kind: "queue",
+    label: "Queue depth",
+    unit: "jobs",
+    symbol: "Q",
+    shape: "bands",
+    min: 4,
+    max: 84,
+  },
+];
+
+const GAP = 4;
+const FLOOR_PAD = 22;
+const TOP_SAFE_PAD = 92;
+const MIN_BLOCK_HEIGHT = 44;
+const MAX_BLOCK_HEIGHT = 116;
+const FEED_LIMIT = 9;
+const INITIAL_STAGE: StageSize = { width: 900, height: 520 };
+
+const metricByKind = new Map(METRICS.map((metric) => [metric.kind, metric]));
+
+function clamp(value: number, min: number, max: number) {
+  return Math.min(max, Math.max(min, value));
+}
+
+function randomBetween(min: number, max: number) {
+  return min + Math.random() * (max - min);
+}
+
+function weightedValue(metric: MetricDefinition) {
+  const normal = randomBetween(metric.min, metric.max);
+  const spike = randomBetween(metric.max * 0.72, metric.max);
+  return Math.random() > 0.78 ? spike : normal;
+}
+
+function formatValue(metric: MetricDefinition, value: number) {
+  if (metric.kind === "throughput") {
+    return `${Math.round(value).toLocaleString()}${metric.unit}`;
+  }
+
+  if (metric.kind === "errors") {
+    return `${value.toFixed(1)}${metric.unit}`;
+  }
+
+  return `${Math.round(value)}${metric.unit}`;
+}
+
+function blockHeight(metric: MetricDefinition, value: number) {
+  const normalized = (value - metric.min) / (metric.max - metric.min);
+  return Math.round(
+    MIN_BLOCK_HEIGHT + clamp(normalized, 0, 1) * (MAX_BLOCK_HEIGHT - MIN_BLOCK_HEIGHT),
+  );
+}
+
+function toneFor(metric: MetricDefinition, value: number): FeedEvent["tone"] {
+  const normalized = (value - metric.min) / (metric.max - metric.min);
+
+  if (metric.kind === "errors" && normalized > 0.5) {
+    return "hot";
+  }
+
+  if (normalized > 0.82) {
+    return "hot";
+  }
+
+  if (normalized > 0.64) {
+    return "warn";
+  }
+
+  return "normal";
+}
+
+function totalLaneHeight(blocks: MetricBlock[], lane: number) {
+  const laneBlocks = blocks.filter((block) => block.lane === lane);
+
+  if (laneBlocks.length === 0) {
+    return 0;
+  }
+
+  return laneBlocks.reduce((total, block) => total + block.height, 0) + (laneBlocks.length - 1) * GAP;
+}
+
+function compactLane(blocks: MetricBlock[], lane: number, stageHeight: number) {
+  let barrier = stageHeight - FLOOR_PAD;
+
+  return blocks.map((block) => {
+    if (block.lane !== lane || block.state !== "settled") {
+      return block;
+    }
+
+    const y = barrier - block.height;
+    barrier = y - GAP;
+
+    return {
+      ...block,
+      y,
+      velocity: 0,
+    };
+  });
+}
+
+function pruneLane(blocks: MetricBlock[], lane: number, stageHeight: number) {
+  const maxHeight = stageHeight - TOP_SAFE_PAD;
+  let next = blocks;
+
+  while (totalLaneHeight(next, lane) > maxHeight) {
+    const oldestSettled = next
+      .filter((block) => block.lane === lane && block.state === "settled")
+      .sort((a, b) => a.createdAt - b.createdAt)[0];
+
+    if (!oldestSettled) {
+      break;
+    }
+
+    next = next.filter((block) => block.id !== oldestSettled.id);
+  }
+
+  return compactLane(next, lane, stageHeight);
+}
+
+function stepBlocks(blocks: MetricBlock[], dt: number, stageHeight: number) {
+  const moved = blocks.map((block) => {
+    if (block.state !== "falling") {
+      return block;
+    }
+
+    const velocity = Math.min(block.velocity + 1150 * dt, 820);
+    return {
+      ...block,
+      velocity,
+      y: block.y + velocity * dt,
+    };
+  });
+
+  const byId = new Map<number, MetricBlock>(moved.map((block) => [block.id, block]));
+
+  for (const metric of METRICS) {
+    const laneBlocks = moved
+      .filter((block) => block.lane === METRICS.indexOf(metric))
+      .sort((a, b) => b.y + b.height - (a.y + a.height));
+    let barrier = stageHeight - FLOOR_PAD;
+
+    for (const block of laneBlocks) {
+      const updated = byId.get(block.id);
+
+      if (!updated) {
+        continue;
+      }
+
+      if (updated.y + updated.height >= barrier) {
+        const y = barrier - updated.height;
+        byId.set(updated.id, {
+          ...updated,
+          y,
+          velocity: 0,
+          state: "settled",
+        });
+        barrier = y - GAP;
+      } else {
+        barrier = updated.y - GAP;
+      }
+    }
+  }
+
+  let next = Array.from(byId.values()).sort((a, b) => a.createdAt - b.createdAt);
+
+  for (const metric of METRICS) {
+    next = pruneLane(next, METRICS.indexOf(metric), stageHeight);
+  }
+
+  return next;
+}
+
+function useStageSize(stageRef: React.RefObject<HTMLDivElement | null>) {
+  const [stageSize, setStageSize] = useState<StageSize>(INITIAL_STAGE);
+
+  useLayoutEffect(() => {
+    if (!stageRef.current) {
+      return undefined;
+    }
+
+    const observer = new ResizeObserver(([entry]) => {
+      if (!entry) {
+        return;
+      }
+
+      setStageSize({
+        width: Math.round(entry.contentRect.width),
+        height: Math.round(entry.contentRect.height),
+      });
+    });
+
+    observer.observe(stageRef.current);
+
+    return () => observer.disconnect();
+  }, [stageRef]);
+
+  return stageSize;
+}
