+  font-size: 0.9rem;
+  font-weight: 800;
+}
+
+.primary-button,
+.icon-button {
+  border: 1px solid #254845;
+  color: #ffffff;
+  background: #254845;
+  transition:
+    transform 140ms ease,
+    background-color 140ms ease,
+    border-color 140ms ease;
+}
+
+.primary-button {
+  min-width: 112px;
+  padding: 0 15px;
+}
+
+.icon-button {
+  min-width: 92px;
+  padding: 0 12px;
+  color: #2b2b28;
+  border-color: #d2c8ba;
+  background: #fbfaf6;
+}
+
+.primary-button:hover,
+.icon-button:hover {
+  transform: translateY(-1px);
+}
+
+.primary-button:focus-visible,
+.icon-button:focus-visible,
+.switch-control:focus-within {
+  outline: 3px solid #b9682f;
+  outline-offset: 3px;
+}
+
+.switch-control {
+  position: relative;
+  min-width: 176px;
+  padding: 0 12px;
+  color: #2c332f;
+  border: 1px solid #d2c8ba;
+  background: #fbfaf6;
+}
+
+.switch-control input {
+  position: absolute;
+  inline-size: 1px;
+  block-size: 1px;
+  opacity: 0;
+}
+
+.switch-track {
+  position: relative;
+  width: 36px;
+  height: 20px;
+  flex: 0 0 auto;
+  border: 1px solid #81766a;
+  border-radius: 999px;
+  background: #d8d2c7;
+}
+
+.switch-track::after {
+  position: absolute;
+  top: 3px;
+  left: 3px;
+  width: 12px;
+  height: 12px;
+  border-radius: 50%;
+  background: #ffffff;
+  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.22);
+  content: "";
+  transition: transform 160ms ease;
+}
+
+.switch-control input:checked + .switch-track {
+  border-color: #1d5f56;
+  background: #1d5f56;
+}
+
+.switch-control input:checked + .switch-track::after {
+  transform: translateX(16px);
+}
+
+.dashboard-grid {
+  display: grid;
+  grid-template-columns: minmax(0, 1fr) 350px;
+  gap: 18px;
+  margin-top: 18px;
+  align-items: stretch;
+}
+
+.rain-panel,
+.feed-panel {
+  border-radius: 8px;
+}
+
+.rain-panel {
+  min-width: 0;
+  overflow: hidden;
+}
+
+.stage-header,
+.feed-heading {
+  display: flex;
+  align-items: flex-start;
+  justify-content: space-between;
+  gap: 18px;
+  padding: 18px;
+}
+
+.legend {
+  display: flex;
+  flex-wrap: wrap;
+  justify-content: flex-end;
+  gap: 8px;
+  max-width: 600px;
+}
+
+.legend-item {
+  display: inline-flex;
+  align-items: center;
+  gap: 7px;
+  min-height: 30px;
+  padding: 4px 8px 4px 5px;
+  border: 1px solid #d8d0c2;
+  border-radius: 999px;
+  color: #3a352e;
+  background: #fffdfa;
+  font-size: 0.78rem;
+  font-weight: 800;
+}
+
+.legend-swatch {
+  display: grid;
+  place-items: center;
+  width: 22px;
+  height: 22px;
+  border-radius: 5px;
+  color: #ffffff;
+  font-size: 0.72rem;
+  font-weight: 900;
+}
+
+.rain-stage {
+  position: relative;
+  height: clamp(480px, 61vh, 690px);
+  margin: 0 18px 18px;
+  overflow: hidden;
+  border: 1px solid #cfc6b8;
+  border-radius: 8px;
+  background:
+    linear-gradient(180deg, rgba(255, 255, 255, 0.84), rgba(236, 232, 221, 0.94)),
+    repeating-linear-gradient(0deg, transparent 0 43px, rgba(39, 45, 43, 0.08) 43px 44px);
+}
+
+.rain-stage.reduced::after {
+  position: absolute;
+  right: 12px;
+  bottom: 12px;
+  z-index: 7;
+  padding: 7px 9px;
+  border: 1px solid #d0c7b8;
+  border-radius: 999px;
+  color: #46413a;
+  background: rgba(255, 253, 248, 0.94);
+  font-size: 0.77rem;
+  font-weight: 850;
+  content: "reduced motion";
+}
+
+.lane-guide {
+  position: absolute;
+  top: 0;
+  bottom: 0;
+  z-index: 1;
+  display: flex;
+  align-items: flex-start;
+  justify-content: center;
+  gap: 6px;
+  padding-top: 12px;
+  border-right: 1px dashed rgba(76, 71, 63, 0.24);
+  color: #554c43;
+  font-size: 0.74rem;
+  font-weight: 850;
+  pointer-events: none;
+}
+
+.lane-guide:last-of-type {
+  border-right: 0;
+}
+
+.lane-badge {
+  display: grid;
+  place-items: center;
+  width: 21px;
+  height: 21px;
+  border-radius: 5px;
+  color: #ffffff;
+  font-size: 0.72rem;
+  font-weight: 950;
+}
+
+.floor-line {
+  position: absolute;
+  right: 0;
+  bottom: 22px;
+  left: 0;
+  z-index: 2;
+  height: 3px;
+  background:
+    repeating-linear-gradient(
+      90deg,
+      rgba(37, 72, 69, 0.92) 0 18px,
+      rgba(37, 72, 69, 0.2) 18px 28px
+    );
+}
+
+.metric-bar {
+  position: absolute;
+  top: 0;
+  left: 0;
+  z-index: 4;
+  display: grid;
+  grid-template-columns: 24px minmax(0, 1fr);
+  grid-template-rows: auto 1fr;
+  align-items: center;
+  gap: 2px 6px;
+  min-height: 44px;
+  padding: 7px 8px;
+  overflow: hidden;
+  border: 2px solid rgba(30, 36, 35, 0.68);
+  border-radius: 7px 7px 3px 3px;
+  color: #ffffff;
+  box-shadow:
+    0 8px 14px rgba(41, 38, 34, 0.18),
+    inset 0 0 0 1px rgba(255, 255, 255, 0.2);
+  will-change: transform;
+}
+
+.metric-bar.settled {
+  border-bottom-width: 4px;
+  box-shadow:
+    0 4px 8px rgba(41, 38, 34, 0.15),
+    inset 0 0 0 1px rgba(255, 255, 255, 0.2);
+}
+
+.metric-bar.falling {
+  filter: saturate(1.06);
+}
+
+.bar-symbol,
+.feed-symbol {
+  display: grid;
+  place-items: center;
+  border: 1px solid rgba(255, 255, 255, 0.72);
+  border-radius: 5px;
+  color: #ffffff;
+  background: rgba(0, 0, 0, 0.18);
+  font-weight: 950;
+}
+
+.bar-symbol {
+  grid-row: 1 / 3;
+  width: 24px;
+  height: 24px;
+  font-size: 0.72rem;
+}
+
+.bar-label {
+  overflow: hidden;
+  font-size: 0.66rem;
+  font-weight: 850;
+  line-height: 1.05;
+  text-overflow: ellipsis;
+  text-shadow: 0 1px 1px rgba(0, 0, 0, 0.28);
+  white-space: nowrap;
+}
+
+.metric-bar strong {
+  font-size: 0.8rem;
+  line-height: 1.05;
+  text-shadow: 0 1px 1px rgba(0, 0, 0, 0.28);
+}
+
+.latency {
+  --metric-color: #246a73;
+}
+
+.cpu {
+  --metric-color: #7753a2;
+}
+
+.throughput {
+  --metric-color: #2d7a55;
+}
+
+.errors {
+  --metric-color: #a94738;
+}
+
+.queue {
+  --metric-color: #9b6a18;
+}
+
+.metric-bar,
+.legend-swatch,
+.lane-badge {
+  background-color: var(--metric-color);
+}
+
+.pattern-stripe {
+  background-image: repeating-linear-gradient(
+    135deg,
+    rgba(255, 255, 255, 0.22) 0 6px,
+    rgba(255, 255, 255, 0) 6px 12px
+  );
+}
+
+.pattern-dots {
+  background-image: radial-gradient(rgba(255, 255, 255, 0.34) 1.5px, transparent 1.5px);
+  background-size: 11px 11px;
+}
+
+.pattern-grid {
+  background-image:
+    linear-gradient(rgba(255, 255, 255, 0.24) 1px, transparent 1px),
+    linear-gradient(90deg, rgba(255, 255, 255, 0.24) 1px, transparent 1px);
+  background-size: 13px 13px;
+}
+
+.pattern-slash {
+  background-image:
+    repeating-linear-gradient(
+      45deg,
+      rgba(255, 255, 255, 0.28) 0 4px,
+      rgba(255, 255, 255, 0) 4px 10px
+    ),
+    repeating-linear-gradient(
+      -45deg,
+      rgba(0, 0, 0, 0.12) 0 5px,
+      rgba(0, 0, 0, 0) 5px 12px
+    );
+}
+
+.pattern-bands {
+  background-image: repeating-linear-gradient(
+    0deg,
+    rgba(255, 255, 255, 0.25) 0 5px,
+    rgba(255, 255, 255, 0) 5px 14px
+  );
+}
+
+.feed-panel {
+  display: flex;
+  flex-direction: column;
+  min-width: 0;
+  padding-bottom: 16px;
+}
+
+.feed-heading svg {
+  flex: 0 0 auto;
+  color: #355652;
+}
+
+.metric-summary {
+  display: grid;
+  grid-template-columns: 1fr;
+  gap: 8px;
+  padding: 0 18px 14px;
+}
+
+.metric-summary div {
+  display: flex;
+  align-items: center;
+  gap: 9px;
+  min-height: 38px;
+  padding: 9px 10px;
+  border: 1px solid #d8d0c2;
+  border-radius: 8px;
+  color: #38322c;
+  background: #fffdfa;
+  font-size: 0.86rem;
+  font-weight: 800;
+}
+
+.feed-list {
+  display: flex;
+  flex-direction: column;
+  gap: 8px;
+  min-height: 330px;
+  margin: 0;
+  padding: 0 18px;
+  list-style: none;
+}
+
+.feed-item,
+.empty-feed {
+  min-height: 45px;
+  border-radius: 8px;
+}
+
+.feed-item {
+  display: grid;
+  grid-template-columns: 30px minmax(0, 1fr) auto 18px;
+  align-items: center;
+  gap: 9px;
+  padding: 8px;
+  border: 1px solid color-mix(in srgb, var(--metric-color) 38%, #d7d1c5);
+  color: #2c2823;
+  background: color-mix(in srgb, var(--metric-color) 12%, #fffdfa);
+}
+
+.feed-item.hot {
+  border-style: solid;
+  box-shadow: inset 4px 0 0 var(--metric-color);
+}
+
+.feed-item.warn {
+  border-style: dashed;
+}
+
+.feed-symbol {
+  width: 30px;
+  height: 30px;
+  background: var(--metric-color);
+  font-size: 0.8rem;
+}
+
+.feed-label {
+  overflow: hidden;
+  font-size: 0.86rem;
+  font-weight: 850;
+  text-overflow: ellipsis;
+  white-space: nowrap;
+}
+
+.feed-item strong {
+  font-size: 0.86rem;
+}
+
+.feed-item svg {
+  color: var(--metric-color);
+}
+
+.empty-feed {
+  display: grid;
+  place-items: center;
+  border: 1px dashed #cfc6b8;
+  color: #6e665c;
+  background: #fffdfa;
+  font-weight: 800;
+}
+
+.lane-counts {
+  display: grid;
+  grid-template-columns: repeat(5, 1fr);
+  gap: 7px;
+  margin-top: auto;
+  padding: 18px 18px 0;
+}
+
+.lane-count {
+  display: grid;
+  gap: 2px;
+  justify-items: center;
+  min-width: 0;
+  padding: 8px 4px;
+  border: 1px solid color-mix(in srgb, var(--metric-color) 32%, #d7d1c5);
+  border-radius: 8px;
+  background: color-mix(in srgb, var(--metric-color) 10%, #fffdfa);
+}
+
+.lane-count span {
+  display: grid;
+  place-items: center;
+  width: 23px;
+  height: 23px;
+  border-radius: 5px;
+  color: #ffffff;
+  background: var(--metric-color);
+  font-size: 0.72rem;
+  font-weight: 950;
+}
+
+.lane-count strong {
+  font-size: 1rem;
+  line-height: 1;
+}
+
+.lane-count small {
+  max-width: 100%;
+  overflow: hidden;
+  color: #6d6257;
+  font-size: 0.62rem;
+  font-weight: 850;
+  text-overflow: ellipsis;
+  white-space: nowrap;
+}
+
+@media (prefers-reduced-motion: reduce) {
+  *,
+  *::before,
+  *::after {
+    scroll-behavior: auto !important;
+    transition-duration: 0.01ms !important;
+    animation-duration: 0.01ms !important;
+    animation-iteration-count: 1 !important;
+  }
+}
+
+@media (max-width: 1100px) {
+  .control-band {
+    grid-template-columns: 1fr;
+  }
+
+  .status-strip,
+  .controls {
+    justify-content: flex-start;
+  }
+
+  .dashboard-grid {
+    grid-template-columns: 1fr;
+  }
+
+  .feed-panel {
+    min-height: auto;
+  }
+
+  .feed-list {
+    min-height: 0;
+  }
+}
+
+@media (max-width: 740px) {
+  .app-shell {
+    width: min(100vw - 18px, 1420px);
+    padding-top: 9px;
+  }
+
+  .control-band,
+  .stage-header,
+  .feed-heading {
+    padding: 14px;
+  }
+
+  .brand-mark {
+    width: 46px;
+    height: 46px;
+  }
+
+  .controls {
+    display: grid;
+    grid-template-columns: 1fr 1fr;
+  }
+
+  .primary-button,
+  .icon-button,
+  .switch-control {
+    width: 100%;
+    min-width: 0;
+  }
+
+  .switch-control {
+    grid-column: 1 / -1;
+  }
+
+  .stage-header {
+    display: grid;
+  }
+
+  .legend {
+    justify-content: flex-start;
+  }
+
+  .rain-stage {
+    height: 520px;
+    margin: 0 10px 10px;
+  }
+
+  .lane-guide {
+    align-items: center;
+    justify-content: flex-start;
+    padding: 8px 0 0 4px;
+    writing-mode: vertical-rl;
+  }
+
+  .lane-badge {
+    width: 18px;
+    height: 18px;
+  }
+
+  .metric-bar {
+    grid-template-columns: 1fr;
+    grid-template-rows: 18px 1fr auto;
+    justify-items: center;
+    gap: 1px;
+    padding: 6px 4px;
+  }
+
+  .bar-symbol {
+    grid-row: auto;
+    width: 19px;
+    height: 19px;
+  }
+
+  .bar-label,
+  .metric-bar strong {
+    max-width: 100%;
+    font-size: 0.6rem;
+    text-align: center;
+  }
+
+  .lane-counts {
+    grid-template-columns: repeat(5, minmax(0, 1fr));
+  }
+}
